class Solution:
    def possibleStringCount(self, word):
        n = len(word)
        runs = []
        i = 0
        while i < n:
            j = i
            while j < n and word[j] == word[i]:
                j += 1
            runs.append(j - i)
            i = j
        total = 1
        for g in runs:
            total += (g - 1)
        return total

